SET FOREIGN_KEY_CHECKS = 0;
DELETE FROM messages WHERE dialogId IN (SELECT id FROM (SELECT d.id FROM dialogs d JOIN contacts c ON d.contactId = c.id WHERE c.telegramId LIKE 'channel_%' OR c.telegramId LIKE 'group_%') AS tmp);
DELETE FROM dialog_tags WHERE dialogId IN (SELECT id FROM (SELECT d.id FROM dialogs d JOIN contacts c ON d.contactId = c.id WHERE c.telegramId LIKE 'channel_%' OR c.telegramId LIKE 'group_%') AS tmp);
DELETE FROM dialogs WHERE id IN (SELECT id FROM (SELECT d.id FROM dialogs d JOIN contacts c ON d.contactId = c.id WHERE c.telegramId LIKE 'channel_%' OR c.telegramId LIKE 'group_%') AS tmp);
DELETE FROM contacts WHERE telegramId LIKE 'channel_%' OR telegramId LIKE 'group_%';
SET FOREIGN_KEY_CHECKS = 1;
SELECT COUNT(*) as dialogs FROM dialogs;
SELECT COUNT(*) as contacts FROM contacts;

